import{c as t,Q as o,j as i,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Tenant Import — Idempotent Rewrite Plan","description":"","frontmatter":{},"headers":[],"relativePath":"tenant-import-idempotent.md","filePath":"tenant-import-idempotent.md","lastUpdated":1778829398000}'),a={name:"tenant-import-idempotent.md"};function r(n,e,l,d,c,p){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="tenant-import-—-idempotent-rewrite-plan" tabindex="-1">Tenant Import — Idempotent Rewrite Plan <a class="header-anchor" href="#tenant-import-—-idempotent-rewrite-plan" aria-label="Permalink to &quot;Tenant Import — Idempotent Rewrite Plan&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>Current <code>tenant-import</code> is not idempotent. Every non-user document receives a fresh <code>bson.NewObjectID()</code> on insert (<a href="./../internal/migrate/import.go#L306">internal/migrate/import.go:306</a>), but cross-document <code>_id</code> references (e.g. <code>parentId</code> in a sub-table pointing at a main-table record&#39;s <code>_id</code>) are <strong>not</strong> rewired. Re-runs also insert duplicate documents because the insert path uses plain <code>InsertMany</code>, not upserts.</p><p>Consequences:</p><ul><li>Parent→child relationships broken silently after import (child&#39;s <code>parentId</code> still holds the source <code>_id</code>, but the parent now has a fresh one).</li><li>Re-running the tool against a partially-imported tenant creates duplicates instead of resuming.</li><li>Only the <code>user</code> collection has a de-duplication path (<code>--reuse-existing-users</code>).</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ol><li>Idempotent imports: re-running the tool against the same target must converge, not duplicate.</li><li>Preserve cross-document <code>_id</code> references after import.</li><li>Bounded memory footprint suitable for k8s pods (≤ 512 MB).</li><li>Resumable / retry-safe on partial failure.</li></ol><h2 id="algorithm" tabindex="-1">Algorithm <a class="header-anchor" href="#algorithm" aria-label="Permalink to &quot;Algorithm&quot;">​</a></h2><h3 id="classification-three-cases-per-source-id" tabindex="-1">Classification (three cases per source <code>_id</code>) <a class="header-anchor" href="#classification-three-cases-per-source-id" aria-label="Permalink to &quot;Classification (three cases per source `_id`)&quot;">​</a></h3><p>For each source document, look up <code>{_id: src._id}</code> in the target collection:</p><table tabindex="0"><thead><tr><th>Case</th><th>Target state</th><th>Action</th></tr></thead><tbody><tr><td>1</td><td>Exists, <code>tenantId == targetTenantID</code></td><td>Keep <code>_id</code>. No remap. Upsert by <code>{_id, tenantId}</code>.</td></tr><tr><td>2</td><td>Does not exist</td><td>Keep <code>_id</code>. No remap. Upsert by <code>{_id, tenantId}</code>.</td></tr><tr><td>3</td><td>Exists, <code>tenantId != targetTenantID</code> (cross-tenant clash)</td><td>Allocate new <code>_id</code>. Record <code>srcHex → newOID</code> in <code>idMap</code>. Upsert.</td></tr></tbody></table><p>Only case 3 produces an <code>idMap</code> entry. Cases 1 and 2 preserve the source <code>_id</code> so references remain intact without any rewriting.</p><h3 id="two-pass-flow" tabindex="-1">Two-pass flow <a class="header-anchor" href="#two-pass-flow" aria-label="Permalink to &quot;Two-pass flow&quot;">​</a></h3><p>Pass 1 must complete for <strong>every</strong> collection before Pass 2 touches the database, because a document in collection A may reference a document in collection B via <code>_id</code>; the deep-walk in Pass 2 needs the full global <code>idMap</code>.</p><p><strong>Pass 1 — Classify (no writes):</strong></p><ol><li>Walk zip entries. Skip empty collections entirely (don&#39;t load the zip entry).</li><li>For each non-empty source collection (that isn&#39;t in the skip list below): <ul><li>Stream source <code>_id</code>s in chunks of 10 000.</li><li>For each chunk: <code>target.find({_id: {$in: chunk}}, {_id:1, tenantId:1})</code>.</li><li>Classify each source <code>_id</code> into case 1 / 2 / 3.</li><li>Case 3 entries: append to global <code>idMap</code> and per-collection <code>remapSet</code>.</li></ul></li><li>When the <code>user</code> collection is processed via the existing <code>ReuseExistingUsers</code> flow, its OID remappings are written into the <strong>same</strong> global <code>idMap</code> so non-user documents that reference users are rewired correctly by Pass 2.</li></ol><p><strong>Pass 2 — Apply and upsert:</strong></p><ol><li>If <code>len(idMap) == 0</code>, skip the deep-walk entirely (fast path).</li><li>Otherwise, for each collection: <ul><li>Re-stream source documents one at a time.</li><li>If <code>doc._id ∈ remapSet</code>, swap in the new OID from <code>idMap</code>.</li><li>Deep-walk <strong>every field at every depth</strong>, replacing any <code>bson.ObjectID</code> value matching an <code>idMap</code> key.</li><li>Apply tenant-ref rewrite (<code>rewriteTenantRefs</code>, unchanged).</li><li>Append to batch. On reaching <code>batchSize</code>, issue an unordered <code>bulkWrite</code> of upserts filtered by <code>{_id, tenantId}</code>.</li></ul></li></ol><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><h3 id="collections-skipped-by-the-new-algorithm" tabindex="-1">Collections skipped by the new algorithm <a class="header-anchor" href="#collections-skipped-by-the-new-algorithm" aria-label="Permalink to &quot;Collections skipped by the new algorithm&quot;">​</a></h3><p>These collections are <strong>not</strong> classified, have no <code>_id</code> map entry created, and are <strong>not</strong> deep-walked in Pass 2:</p><ul><li><code>user</code> — owned by the existing <code>ReuseExistingUsers</code> path (email-based dedupe). Its OID remappings still flow into the global <code>idMap</code> for use by other collections.</li><li><code>user-session</code> — ephemeral, no meaningful cross-document references.</li><li><code>customer</code> — dedupe driven by business keys, not <code>_id</code>.</li></ul><h3 id="deep-walk-scope" tabindex="-1">Deep-walk scope <a class="header-anchor" href="#deep-walk-scope" aria-label="Permalink to &quot;Deep-walk scope&quot;">​</a></h3><p>Two independent walks with different scopes — <strong>do not conflate</strong>:</p><table tabindex="0"><thead><tr><th>Walk</th><th>Purpose</th><th>Scope</th></tr></thead><tbody><tr><td>User remap</td><td>Existing email/OID anonymisation</td><td>Known field list (<a href="./../internal/migrate/remap.go#L52-L89">remap.go:52-89</a>) + <code>customFields</code> subtree</td></tr><tr><td><code>idMap</code> rewrite (new)</td><td>Cross-document <code>_id</code> integrity</td><td><strong>All fields, every depth</strong> — any <code>bson.ObjectID</code> value anywhere in the document</td></tr></tbody></table><h2 id="idmap-storage" tabindex="-1"><code>idMap</code> storage <a class="header-anchor" href="#idmap-storage" aria-label="Permalink to &quot;`idMap` storage&quot;">​</a></h2><ul><li>In-memory <code>map[string]bson.ObjectID</code> by default.</li><li>Threshold: <strong>500 000 entries</strong> (~40 MB in memory). Above this, spill to disk.</li><li>Disk backend: <strong>bbolt</strong> (<code>go.etcd.io/bbolt</code>) — pure Go, no CGO, single file. <ul><li>File: <code>&lt;os.TempDir()&gt;/tenant-import-&lt;jobID&gt;.bolt</code></li><li>Single bucket <code>idmap</code>. Key = source hex string (24 bytes). Value = 12-byte <code>ObjectID</code>.</li><li>In-memory LRU cache (100k hot entries) sits in front of bolt to keep Pass 2 deep-walk lookups fast.</li></ul></li><li>Cleanup: <code>defer os.Remove(path)</code> at the end of <code>RunImport</code>. Also invoked via panic-recovery wrapper so a crash never leaks the file.</li></ul><h3 id="idmap-interface" tabindex="-1"><code>IDMap</code> interface <a class="header-anchor" href="#idmap-interface" aria-label="Permalink to &quot;`IDMap` interface&quot;">​</a></h3><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IDMap</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> interface</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    Get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">srcHex</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bson</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ObjectID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    Put</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">srcHex</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">newOID</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bson</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ObjectID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    Len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    Close</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">error</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // releases bolt resources and deletes file if backed by disk</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Implementations:</p><ul><li><code>memIDMap</code> — plain <code>map[string]bson.ObjectID</code>.</li><li><code>boltIDMap</code> — bbolt-backed with LRU cache. Constructed when <code>memIDMap.Len()</code> crosses the threshold by draining the map into bolt.</li></ul><p>Deep-walk code consumes the interface and is agnostic to storage.</p><h2 id="memory-profile" tabindex="-1">Memory profile <a class="header-anchor" href="#memory-profile" aria-label="Permalink to &quot;Memory profile&quot;">​</a></h2><p>Target: comfortably under 512 MB in a k8s pod for 2 M documents × 300 collections.</p><table tabindex="0"><thead><tr><th>Stage</th><th>In-mem working set</th></tr></thead><tbody><tr><td>Pass 1 chunk</td><td>10 000 OIDs × 12 B = ~240 KB + target reply</td></tr><tr><td>Pass 1 <code>idMap</code> (in-mem)</td><td>Case-3 entries × 80 B; capped at 500 k = 40 MB before spill</td></tr><tr><td>Pass 1 <code>idMap</code> (spilled)</td><td>LRU cache 100 k × 80 B = 8 MB</td></tr><tr><td>Pass 2 batch</td><td><code>batchSize</code> × avg doc size (~5–10 MB at batch = 1000)</td></tr><tr><td>Pass 2 deep-walk scratch</td><td>Bounded per document; no accumulation</td></tr></tbody></table><p>Notes:</p><ul><li><code>remapSet</code> per collection is typically empty (case 3 is rare). If large, also eligible for bolt spill (deferred; implement only if observed).</li><li>Source document streaming replaces the current full-collection-into-slice read at <a href="./../internal/migrate/import.go#L194">import.go:194</a>.</li></ul><h2 id="implementation-steps" tabindex="-1">Implementation steps <a class="header-anchor" href="#implementation-steps" aria-label="Permalink to &quot;Implementation steps&quot;">​</a></h2><ol><li><strong>Streaming doc reader.</strong> Replace <code>readJSONLDocs</code> / <code>readBSONDocs</code> with iterator variants (<code>forEachJSONLDoc</code>, <code>forEachBSONDoc</code>) that invoke a callback per document. Keep the slice-returning versions for callers that still need them (tests, user-coll pre-scan).</li><li><strong><code>IDMap</code> interface + backends.</strong><ul><li><code>memIDMap</code> (trivial).</li><li><code>boltIDMap</code> with LRU. Add <code>go.etcd.io/bbolt</code> to <code>go.mod</code>.</li><li>Migration helper: <code>drainMemToBolt(mem, bolt)</code>.</li></ul></li><li><strong>Pass 1 classifier.</strong><ul><li>New file <code>internal/migrate/classify.go</code>.</li><li>Entry point: <code>func classifyCollections(ctx, zr, targetDB, targetTenantID, skipList) (IDMap, map[string]*RemapSet, error)</code>.</li><li>Per collection: stream <code>_id</code>s, chunk $in queries, populate <code>IDMap</code> and <code>RemapSet</code>.</li></ul></li><li><strong>Integrate user-coll flow.</strong><ul><li>Feed existing <code>ReuseExistingUsers</code> OID remappings into the same <code>IDMap</code> so Pass 2 rewires user references in non-user docs.</li><li>Disable the post-insert user remap sweep for case 3 when running under the new algorithm (its work is done during Pass 2).</li></ul></li><li><strong>Pass 2 rewriter.</strong><ul><li>Replace the current &quot;assign new <code>_id</code> and insert&quot; block (<a href="./../internal/migrate/import.go#L300-L334">import.go:300-334</a>).</li><li>Per doc: remapSet check → <code>_id</code> swap → full-field deep-walk → tenant-ref rewrite → append to batch.</li><li>Batch write: <code>bulkWrite</code> with <code>ordered: false</code>, filter <code>{_id, tenantId}</code>, update <code>$set: &lt;doc&gt;</code>, <code>upsert: true</code>.</li></ul></li><li><strong>Cleanup.</strong><ul><li><code>defer idMap.Close()</code> removes bolt file.</li><li>Panic-recover wrapper in <code>RunImport</code> to guarantee deletion on crash.</li></ul></li><li><strong>Tests.</strong><ul><li>Unit: classifier (three cases), <code>IDMap</code> backends (including mem→bolt spill), deep-walk (nested arrays, customFields, OIDs at depth).</li><li>Integration: re-run import against same target → second run produces zero new documents, zero reference drift.</li><li>Cross-tenant clash: pre-seed target with a clashing <code>_id</code> under a different tenant → verify case 3 path rewires correctly.</li></ul></li></ol><h2 id="progress-reporting" tabindex="-1">Progress reporting <a class="header-anchor" href="#progress-reporting" aria-label="Permalink to &quot;Progress reporting&quot;">​</a></h2><p><code>ProgressFn</code> contract extends to cover two passes:</p><ul><li>0–30 %: Pass 1 (classification + user pre-scan).</li><li>30–95 %: Pass 2 (streaming import + upserts).</li><li>95–100 %: user remap sweep (if any) + cleanup.</li></ul><p>Weights are heuristic; adjust after observing real workloads.</p><h2 id="risks-and-open-questions" tabindex="-1">Risks and open questions <a class="header-anchor" href="#risks-and-open-questions" aria-label="Permalink to &quot;Risks and open questions&quot;">​</a></h2><ul><li><strong>Target scan cost at scale.</strong> Pre-scan issues one <code>$in</code> query per chunk per collection. For 300 collections × 200 chunks = 60 000 queries. Batched and projection-limited, this should be seconds, but needs validation on prod-sized tenants. If hot, consider parallelising per-collection scans with a small worker pool.</li><li><strong>Bolt sync mode.</strong> Use <code>db.NoSync = true</code>. The bolt file is ephemeral (deleted at end of job, never reopened across process restarts). Reads within the same process always see prior writes regardless of <code>NoSync</code> because bbolt serves them from its in-memory B+tree, so Pass 2 lookups are consistent with Pass 1 writes. The only durability <code>NoSync</code> sacrifices is &quot;survive a process crash&quot; — and in that scenario we throw the file away and re-run the job anyway.</li><li><strong>Business-key dedupe on other collections.</strong> Collections beyond <code>user</code> / <code>customer</code> may have unique indexes on non-<code>_id</code> fields (e.g. <code>code</code>, <code>slug</code>). Upsert on <code>_id</code> won&#39;t catch these. Not in scope for this change, but flag in the PR description.</li><li><strong>Upsert with <code>$set: &lt;entire doc&gt;</code></strong> replaces the existing target document wholesale on re-run. Confirm this matches the desired idempotent semantics (rather than merge or skip-if-exists).</li><li><strong>Indexes.</strong> <code>applyIndexesFromZip</code> already idempotent (mongo no-ops on identical specs). No change needed.</li></ul><h2 id="out-of-scope-future" tabindex="-1">Out of scope (future) <a class="header-anchor" href="#out-of-scope-future" aria-label="Permalink to &quot;Out of scope (future)&quot;">​</a></h2><ul><li>Parallel per-collection workers for both passes.</li><li>Incremental / delta imports (only changed documents).</li><li>Dedupe on unique business keys across non-user collections.</li><li>Exposing <code>idMap</code> size / spill state through the worker progress UI.</li></ul>',47)])])}const m=t(a,[["render",r]]);export{u as __pageData,m as default};
